18	void free_worktree(struct worktree *worktree)
19	{
20		if (!worktree)
21			return;
22		free(worktree->path);
23		free(worktree->id);
24		free(worktree->head_ref);
25		free(worktree->lock_reason);
26		free(worktree->prune_reason);
27		free(worktree);
28	}
