204	
205		QSORT(l->items, l->nr, prune_cmp);
206		for (i = 1; i < l->nr; i++) {
207			if (!fspathcmp(l->items[i].string, l->items[i - 1].string))
208				prune_worktree(l->items[i].util, "duplicate entry");
209		}
210	}
