297	static const char *worktree_basename(const char *path, int *olen)
298	{
299		const char *name;
300		int len;
301	
302		len = strlen(path);
303		while (len && is_dir_sep(path[len - 1]))
304			len--;
305	
306		for (name = path + len - 1; name > path; name--)
307			if (is_dir_sep(*name)) {
308				name++;
309				break;
310			}
311	
312		*olen = len;
313		return name;
314	}
